using SeedServerSentEventsResumable;

var client = new SeedServerSentEventsResumableClient();
var items = client.Completions.StreamAsync(new StreamCompletionRequest { Query = "foo" });

await foreach (var item in items)
{
    // do something with item
}

using SeedServerSentEventsResumable;

var client = new SeedServerSentEventsResumableClient();
var items = client.Completions.StreamNonResumableAsync(
    new StreamCompletionRequestNonResumable { Query = "bar" }
);

await foreach (var item in items)
{
    // do something with item
}
